import { ethers } from "ethers";

export const QIE_MAINNET = {
  chainId: 1990,
  hexChainId: "0x7c6",
  chainName: "QIE Mainnet",
  rpcUrls: ["https://rpc1mainnet.qie.digital/"],
  nativeCurrency: {
    name: "QIE",
    symbol: "QIE",
    decimals: 18,
  },
  blockExplorerUrls: ["https://mainnet.qie.digital/"],
};

const WALLET_STORAGE_KEY = "spendgrid.wallet";
const WALLETCONNECT_PROJECT_ID = process.env.REACT_APP_WALLETCONNECT_PROJECT_ID || "SPENDGRID_QIE_MAINNET";
const WALLETCONNECT_ID = "walletconnect";
let activeWalletConnectProvider = null;
const eip6963Providers = [];
const eip6963ProviderInfo = typeof WeakMap !== "undefined" ? new WeakMap() : null;
let eip6963RequestInFlight = false;

const WALLET_PRIORITIES = {
  qie: 0,
  metamask: 1,
  rabby: 2,
  walletconnect: 100,
};

function registerEip6963Provider(event) {
  const provider = event?.detail?.provider;
  const info = event?.detail?.info || {};
  if (!provider) return;

  eip6963ProviderInfo?.set(provider, info);
  const providerKey = getProviderIdentity(provider, info);
  const providerKnown = eip6963Providers.some((knownProvider) => (
    knownProvider === provider || getProviderIdentity(knownProvider) === providerKey
  ));
  if (!providerKnown) {
    eip6963Providers.push(provider);
  }
}

if (typeof window !== "undefined") {
  window.addEventListener?.("eip6963:announceProvider", registerEip6963Provider);
}

function getInjectedProviders() {
  if (typeof window === "undefined") return [];
  const detected = [];
  detected.push(...eip6963Providers);
  if (Array.isArray(window.ethereum?.providers)) {
    detected.push(...window.ethereum.providers);
  }
  if (window.ethereum) {
    detected.push(window.ethereum);
  }

  [
    window.qie,
    window.qieWallet,
    window.qieEthereum,
    window.qie?.ethereum,
    window.qieWallet?.ethereum,
    window.QIEWallet,
    window.QIEWallet?.ethereum,
    window.ethereum?.qie,
    window.ethereum?.qieWallet,
    window.metamask?.ethereum,
    window.rabby?.ethereum,
  ].forEach((provider) => {
    if (provider) detected.push(provider);
  });

  return detected.filter((provider, index, providers) => provider && providers.indexOf(provider) === index);
}

export function requestWalletProviderDiscovery() {
  if (typeof window === "undefined" || eip6963RequestInFlight) return;
  eip6963RequestInFlight = true;
  window.setTimeout(() => {
    try {
      window.dispatchEvent?.(new Event("eip6963:requestProvider"));
    } catch (_error) {
      // Provider discovery must never block rendering.
    } finally {
      window.setTimeout(() => {
        eip6963RequestInFlight = false;
      }, 250);
    }
  }, 0);
}

function getProviderInfo(provider) {
  return provider?.info || provider?.providerInfo || eip6963ProviderInfo?.get(provider) || {};
}

function getProviderIdentity(provider, info = getProviderInfo(provider)) {
  const uuid = info?.uuid || provider?.uuid;
  if (uuid) return `uuid:${uuid}`;

  const rdns = info?.rdns || provider?.rdns;
  const name = info?.name || provider?.walletName || provider?.name;
  if (rdns || name) return `info:${rdns || ""}:${name || ""}`;

  return provider;
}

function isQieProvider(provider) {
  const info = getProviderInfo(provider);
  const rdns = info?.rdns || provider?.rdns || "";
  const name = info?.name || provider?.walletName || provider?.name || "";
  return Boolean(
    provider?.isQIE ||
      provider?.isQie ||
      provider?.isQieWallet ||
      provider?.isQIEWallet ||
      provider?.qieWallet ||
      String(rdns).toLowerCase().includes("qie") ||
      String(name).toLowerCase().includes("qie")
  );
}

function providerLabel(type, index) {
  if (type === "qie") return "QIE Wallet";
  if (type === "metamask") return "MetaMask";
  if (type === "rabby") return "Rabby";
  if (type === "coinbase") return "Coinbase Wallet";
  if (type === "trust") return "Trust Wallet";
  return index === 0 ? "Injected Wallet" : `Injected Wallet ${index + 1}`;
}

function providerKind(provider, index) {
  const info = getProviderInfo(provider);
  const rdns = String(info?.rdns || provider?.rdns || "").toLowerCase();
  const name = String(info?.name || provider?.walletName || provider?.name || "").toLowerCase();
  if (isQieProvider(provider)) return "qie";
  if (provider.isRabby || rdns.includes("rabby") || name.includes("rabby")) return "rabby";
  if (provider.isMetaMask || rdns.includes("metamask") || name.includes("metamask")) return "metamask";
  if (provider.isCoinbaseWallet || rdns.includes("coinbase") || name.includes("coinbase")) return "coinbase";
  if (provider.isTrust || rdns.includes("trust") || name.includes("trust")) return "trust";
  return `injected-${index}`;
}

export function getWalletProviders() {
  const seenKinds = new Set();
  const injected = getInjectedProviders()
    .map((provider, index) => {
      const type = providerKind(provider, index);
      return {
        id: type.startsWith("injected-") ? type : `injected-${type}`,
        type,
        label: providerLabel(type, index),
        subtitle: type === "qie" ? "Recommended for QIE Mainnet" : null,
        provider,
        connector: "injected",
        priority: WALLET_PRIORITIES[type] ?? 10 + index,
      };
    })
    .filter((wallet) => {
      if (wallet.type.startsWith("injected-")) return true;
      if (seenKinds.has(wallet.type)) return false;
      seenKinds.add(wallet.type);
      return true;
    });

  return [
    ...injected,
    {
      id: WALLETCONNECT_ID,
      type: WALLETCONNECT_ID,
      label: "WalletConnect",
      subtitle: "Scan with WalletConnect",
      provider: null,
      connector: WALLETCONNECT_ID,
      priority: WALLET_PRIORITIES.walletconnect,
    },
  ].sort((a, b) => a.priority - b.priority || a.label.localeCompare(b.label));
}

export function getStoredWalletId() {
  try {
    return window.localStorage.getItem(WALLET_STORAGE_KEY);
  } catch (_error) {
    return null;
  }
}

export function clearStoredWallet() {
  try {
    window.localStorage.removeItem(WALLET_STORAGE_KEY);
  } catch (_error) {
    // Storage can be unavailable in privacy-restricted browser contexts.
  }
}

function clearKnownConnectorStorage() {
  if (typeof window === "undefined") return;

  const keyMatchers = [
    WALLET_STORAGE_KEY,
    "walletconnect",
    "wc@2",
    "wagmi",
    "rainbowkit",
    "web3modal",
    "appkit",
    "reown"
  ];
  [window.localStorage, window.sessionStorage].forEach((storage) => {
    if (!storage) return;
    try {
      const keys = [];
      for (let index = 0; index < storage.length; index += 1) {
        const key = storage.key(index);
        if (key && keyMatchers.some((matcher) => key.toLowerCase().includes(matcher.toLowerCase()))) {
          keys.push(key);
        }
      }
      keys.forEach((key) => storage.removeItem(key));
    } catch (_error) {
      // Storage can be unavailable in privacy-restricted browser contexts.
    }
  });
}

export async function clearWalletSession(rawProvider) {
  clearStoredWallet();
  clearKnownConnectorStorage();

  const providers = [
    rawProvider,
    activeWalletConnectProvider
  ].filter(Boolean);

  await Promise.all(providers.map(async (provider) => {
    try {
      if (typeof provider.disconnect === "function") {
        await provider.disconnect();
      } else if (typeof provider.close === "function") {
        await provider.close();
      }
    } catch (_error) {
      // Wallet extensions may reject programmatic disconnect; local state is still cleared.
    }
  }));

  activeWalletConnectProvider = null;
}

export function getProviderById(walletId) {
  const providers = getWalletProviders();
  return providers.find((wallet) => wallet.id === walletId) || null;
}

async function createWalletConnectProvider() {
  if (!WALLETCONNECT_PROJECT_ID || WALLETCONNECT_PROJECT_ID === "SPENDGRID_QIE_MAINNET") {
    throw new Error("REACT_APP_WALLETCONNECT_PROJECT_ID is required for WalletConnect.");
  }

  const { default: EthereumProvider } = await import("@walletconnect/ethereum-provider");
  const provider = await EthereumProvider.init({
    projectId: WALLETCONNECT_PROJECT_ID,
    chains: [QIE_MAINNET.chainId],
    optionalChains: [QIE_MAINNET.chainId],
    showQrModal: true,
    rpcMap: {
      [QIE_MAINNET.chainId]: QIE_MAINNET.rpcUrls[0],
    },
    metadata: {
      name: "SpendGrid",
      description: "SpendGrid AI agent payment dashboard",
      url: window.location.origin,
      icons: [`${window.location.origin}/favicon.ico`],
    },
  });

  await provider.enable();
  activeWalletConnectProvider = provider;
  return provider;
}

export async function connectWallet(walletId) {
  if (!walletId) {
    throw new Error("Select a wallet provider to connect.");
  }

  const selected = getProviderById(walletId);
  if (!selected) {
    throw new Error("Selected wallet provider is not available.");
  }

  const rawProvider = selected.connector === WALLETCONNECT_ID
    ? await createWalletConnectProvider()
    : selected.provider;

  await rawProvider.request({ method: "eth_requestAccounts" });
  const provider = new ethers.BrowserProvider(rawProvider);
  const signer = await provider.getSigner();
  const address = await signer.getAddress();
  const { chainId } = await provider.getNetwork();

  try {
    window.localStorage.setItem(WALLET_STORAGE_KEY, selected.id);
  } catch (_error) {
    // Connection should still succeed when persistent storage is unavailable.
  }

  return {
    provider,
    rawProvider,
    signer,
    address,
    chainId: Number(chainId),
    walletId: selected.id,
    walletLabel: selected.label,
  };
}

export async function switchToQieMainnet(rawProvider) {
  if (!rawProvider) {
    throw new Error("No wallet provider selected.");
  }

  try {
    await rawProvider.request({
      method: "wallet_switchEthereumChain",
      params: [{ chainId: QIE_MAINNET.hexChainId }],
    });
  } catch (error) {
    if (error.code !== 4902) {
      throw error;
    }

    await rawProvider.request({
      method: "wallet_addEthereumChain",
      params: [
        {
          chainId: QIE_MAINNET.hexChainId,
          chainName: QIE_MAINNET.chainName,
          rpcUrls: QIE_MAINNET.rpcUrls,
          nativeCurrency: QIE_MAINNET.nativeCurrency,
          blockExplorerUrls: QIE_MAINNET.blockExplorerUrls,
        },
      ],
    });

    await rawProvider.request({
      method: "wallet_switchEthereumChain",
      params: [{ chainId: QIE_MAINNET.hexChainId }],
    });
  }
}

export async function copyAddress(address) {
  if (!address) return;
  if (navigator.clipboard?.writeText) {
    await navigator.clipboard.writeText(address);
    return;
  }

  const input = document.createElement("textarea");
  input.value = address;
  input.setAttribute("readonly", "");
  input.style.position = "fixed";
  input.style.opacity = "0";
  document.body.appendChild(input);
  input.select();
  document.execCommand("copy");
  document.body.removeChild(input);
}

export function openFaucet() {
  window.open("https://mainnet.qie.digital/", "_blank", "noopener,noreferrer");
}

export async function getBalance(provider, address) {
  const raw = await provider.getBalance(address);
  return ethers.formatEther(raw);
}

export function shortenAddress(address) {
  if (!address) return "";
  return `${address.slice(0, 6)}...${address.slice(-4)}`;
}
